BaseBullet = class("baseBullet")

local BulletList = {}

function BaseBullet.getBullet(bulletId)
    return BulletList[tostring(bulletId)]
end

function BaseBullet:ctor(tower, monster, ejectionsCount, hadAttackList)
    self.config = BulletConfig:getConfigById(tower.config.BulletId)
    self.thrower = tower
    self.target = monster
    self.ejectionsCount = ejectionsCount or 0
    self.hadAttackList = hadAttackList or {}
    self.bulletAttack = self.thrower:getAttackValue()
    self:initSkill()
end

function BaseBullet:initSkill()
    --获取掠夺技能触发成功顺序
    local needCont = 0
    if self.thrower.critProbability then
        self.critSuccess = self.thrower:getSkillSuccess(self.thrower.critProbability)
    end
    if self.thrower.plunderProbability then
        self.plunderSuccess = self.thrower:getSkillSuccess(self.thrower.plunderProbability)
    end
    --发射前伤害计算
    self:updateCurDamage()
end

function BaseBullet:updateCurDamage()
    self.curDamage = math.ceil(self.bulletAttack - self.target:getDefenseValue())
    if self.critSuccess then
        self.curDamage = self.curDamage * self.thrower.critResult
    end
    --伤害预判
    self.target.futureHp = self.target.futureHp - self.curDamage
end

function BaseBullet:shoot(startPos, isEjections)
    if self.entityId then
        --重复发射的情况
        return
    end
    if self.thrower.entityId == 0 then
        --发射失败,回滚伤害预判值
        self.target.futureHp = self.target.futureHp + self.curDamage
        self:onDie()
        return
    end
    local speed = self.config.bulletSpeed
    if isEjections then
        speed = self.config.ejectionsSpeed
    end
    self.entityId = EngineWorld:addCreatureBullet(self.thrower.entityId, self.target.entityId, function(entity)
        self.entity = entity
        BulletList[tostring(entity:hashCode())] = self
        entity:setEnableTracker(false)
        entity:setPosition(startPos)
        entity:setSpeedFactor(speed)
        entity:setBox(self.config.bulletBox)
        if #self.config.bulletSprite == 2 then
            entity:setSprite(self.config.bulletSprite[1] or "", self.config.bulletSprite[2] or "")
            entity:setSpriteScale(self.config.bulletSpriteMultiple or 0.5)
        end
        if self.config.bulletEffect ~= "#" then
            entity:setBombEffect(self.config.bulletEffect)
            entity:setEffectScale(self.config.bulletEffectMultiple or 1)
        end
    end)
end

function BaseBullet:attack()
    --检测弹射逻辑
    self.hadAttackList[tostring(self.target.entityId)] = (self.hadAttackList[tostring(self.target.entityId)] or 0) + 1
    self:checkEjections()
    --掠夺处理
    if self.plunderSuccess then
        if isClient then
            --播放特效
            local effectName = self.thrower.plunderEffect
            self.target:addEffect(effectName, effectName, 1000, 1)
        else
            --加钱
            local player = PlayerManager:getPlayerByUserId(self.thrower.userId)
            if player and player.Wallet then
                player.totalMoney = player.totalMoney + self.thrower.plunderResult
                player.Wallet:addMoney(Define.Money.GameGold, self.thrower.plunderResult)
            end
        end
    end
    --暴击,特效飘字处理
    if isClient then
        if self.critSuccess then
            local effectName = self.thrower.critEffect
            self.target:addEffect(effectName, effectName, 1000, 1)
            self.target:showFloatNumber(self.curDamage, Define.FloatNumberColor.Yellow, 1)
        else
            self.target:showFloatNumber(self.curDamage)
        end
    end
    --击中特效
    if isClient and self.config.boomEffect ~= "#" and GUIMain.openBoom then
        EngineWorld:addSimpleEffect(self.config.boomEffect, self.target.entity:getPosition(), 0, 2000, self.config.boomRange, self.config.boomRange, self.config.boomRange)
    end
    local attackBuffIds = self.thrower.attackBuffIds
    self.target:hurt(self.curDamage, attackBuffIds, self.thrower.userId, function()
        AdditionHelper:additionEject(self.thrower, self.thrower.config.killAdditionIds)
    end)
    self:onDie()
end

function BaseBullet:checkEjections()
    if self.ejectionsCount == 0 then
        return
    end
    self.ejectionsCount = self.ejectionsCount - 1
    local nextTarget = self.target.path:getNextTarget(self.target, self.hadAttackList)
    if nextTarget then
        self.thrower:ejectionsAttack(nextTarget, self.target, self.ejectionsCount, self.hadAttackList)
    end
end

function BaseBullet:onDie()
    BulletList[tostring(self.entityId)] = nil
    self.entityId = 0
end
